
export default {
  async fetch(request, env) {
    const url = new URL(request.url);

    try {
      if (url.pathname === "/assets/logo-oficial.png") {
        return serveLogo();
      }

      if (url.pathname === "/api/install" && request.method === "POST") {
        return json(await install(env));
      }

      if (url.pathname === "/api/login" && request.method === "POST") {
        return await login(request, env);
      }

      if (url.pathname === "/api/logout" && request.method === "POST") {
        return json({ ok: true }, { "Set-Cookie": "pf_session=; Path=/; Max-Age=0; HttpOnly; Secure; SameSite=Lax" });
      }

      if (url.pathname === "/api/me") {
        const user = await requireUser(request, env);
        return json({ ok: true, user: publicUser(user) });
      }

      if (url.pathname === "/api/dashboard") {
        const user = await requireUser(request, env);
        return json(await dashboard(env, user));
      }

      if (url.pathname === "/api/admin/sellers" && request.method === "POST") {
        const user = await requireAdmin(request, env);
        const body = await request.json();
        return json(await createSeller(env, body));
      }

      if (url.pathname === "/api/admin/products" && request.method === "POST") {
        const user = await requireAdmin(request, env);
        const body = await request.json();
        return json(await createProduct(env, body));
      }

      if (url.pathname === "/api/admin/sales" && request.method === "POST") {
        const user = await requireAdmin(request, env);
        const body = await request.json();
        return json(await createSale(env, body));
      }

      if (url.pathname === "/api/admin/pay" && request.method === "POST") {
        const user = await requireAdmin(request, env);
        const body = await request.json();
        return json(await markPaid(env, body));
      }

      if (url.pathname === "/api/seller/withdraw" && request.method === "POST") {
        const user = await requireSeller(request, env);
        return json(await requestWithdraw(env, user));
      }

      return htmlResponse(APP_HTML);
    } catch (err) {
      return json({ ok: false, error: err.message || "Erro inesperado" }, {}, 400);
    }
  }
};

