async function install(env) {
  await env.DB.exec(SCHEMA_SQL);

  const adminExists = await env.DB.prepare("SELECT id FROM users WHERE email=?").bind("admin@pequenaflor.app").first();
  if (!adminExists) {
    const hash = await hashPassword("admin123");
    await env.DB.prepare("INSERT INTO users (name,email,password_hash,role,code,active,created_at) VALUES (?,?,?,?,?,?,datetime('now'))")
      .bind("Jorge / Beth", "admin@pequenaflor.app", hash, "admin", "DONO", 1).run();
  }

  const sellerExists = await env.DB.prepare("SELECT id FROM users WHERE code=?").bind("FLOR01").first();
  if (!sellerExists) {
    const hash = await hashPassword("123456");
    await env.DB.prepare("INSERT INTO users (name,email,password_hash,role,code,active,created_at) VALUES (?,?,?,?,?,?,datetime('now'))")
      .bind("Divulgadora Pequena Flor", "flor01@pequenaflor.app", hash, "seller", "FLOR01", 1).run();
  }

  return { ok: true };
}

const SCHEMA_SQL = `
CREATE TABLE IF NOT EXISTS users (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  email TEXT UNIQUE NOT NULL,
  password_hash TEXT NOT NULL,
  role TEXT NOT NULL CHECK(role IN ('admin','seller')),
  code TEXT UNIQUE,
  active INTEGER DEFAULT 1,
  created_at TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS products (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  price REAL NOT NULL,
  active INTEGER DEFAULT 1,
  created_at TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS sales (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  seller_id INTEGER NOT NULL,
  seller_code TEXT NOT NULL,
  amount REAL NOT NULL,
  commission_rate REAL NOT NULL,
  commission_amount REAL NOT NULL,
  customer_name TEXT,
  status TEXT DEFAULT 'confirmed',
  paid INTEGER DEFAULT 0,
  created_at TEXT NOT NULL,
  FOREIGN KEY(seller_id) REFERENCES users(id)
);

CREATE TABLE IF NOT EXISTS withdraw_requests (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  seller_id INTEGER NOT NULL,
  amount REAL NOT NULL,
  status TEXT DEFAULT 'pending',
  created_at TEXT NOT NULL,
  FOREIGN KEY(seller_id) REFERENCES users(id)
);
`;

async function login(request, env) {
  const { email, password } = await request.json();
  if (!email || !password) throw new Error("Informe e-mail e senha.");

  const user = await env.DB.prepare("SELECT * FROM users WHERE email=? AND active=1").bind(email.toLowerCase()).first();
  if (!user) throw new Error("Usuário não encontrado.");

  const ok = await verifyPassword(password, user.password_hash);
  if (!ok) throw new Error("Senha incorreta.");

  const token = await signToken({ id: user.id, exp: Math.floor(Date.now()/1000) + 86400 * 7 }, env);
  return json({ ok: true, user: publicUser(user) }, {
    "Set-Cookie": `pf_session=${token}; Path=/; Max-Age=${86400*7}; HttpOnly; Secure; SameSite=Lax`
  });
}

async function dashboard(env, user) {
  if (user.role === "admin") {
    const totals = await env.DB.prepare(`
      SELECT 
      COALESCE(SUM(amount),0) sales_total,
      COALESCE(SUM(CASE WHEN paid=0 THEN commission_amount ELSE 0 END),0) pending_commission,
      COALESCE(SUM(CASE WHEN paid=1 THEN commission_amount ELSE 0 END),0) paid_commission,
      (SELECT COUNT(*) FROM users WHERE role='seller' AND active=1) sellers
      FROM sales
    `).first();

    const sales = await env.DB.prepare(`
      SELECT s.*, u.name seller_name, u.code seller_code
      FROM sales s JOIN users u ON u.id=s.seller_id
      ORDER BY s.id DESC LIMIT 20
    `).all();

    return { ok: true, user: publicUser(user), totals, sales: sales.results };
  }

  const totals = await env.DB.prepare(`
    SELECT COUNT(*) count,
    COALESCE(SUM(amount),0) sales_total,
    COALESCE(SUM(CASE WHEN paid=0 THEN commission_amount ELSE 0 END),0) pending_commission,
    COALESCE(SUM(CASE WHEN paid=1 THEN commission_amount ELSE 0 END),0) paid_commission
    FROM sales WHERE seller_id=?
  `).bind(user.id).first();

  const sales = await env.DB.prepare("SELECT * FROM sales WHERE seller_id=? ORDER BY id DESC LIMIT 20").bind(user.id).all();
  return { ok: true, user: publicUser(user), totals, sales: sales.results };
}

async function createSeller(env, body) {
  const name = clean(body.name);
  const email = clean(body.email).toLowerCase();
  const password = String(body.password || "");
  const code = clean(body.code).toUpperCase();

  if (!name || !email || password.length < 6 || !code) throw new Error("Preencha nome, e-mail, senha com 6+ caracteres e código.");

  const hash = await hashPassword(password);
  await env.DB.prepare("INSERT INTO users (name,email,password_hash,role,code,active,created_at) VALUES (?,?,?,?,?,?,datetime('now'))")
    .bind(name, email, hash, "seller", code, 1).run();

  return { ok: true };
}

async function createProduct(env, body) {
  const name = clean(body.name);
  const price = Number(body.price);
  if (!name || !price || price <= 0) throw new Error("Produto e preço são obrigatórios.");
  await env.DB.prepare("INSERT INTO products (name,price,active,created_at) VALUES (?,?,1,datetime('now'))").bind(name, price).run();
  return { ok: true };
}

async function createSale(env, body) {
  const sellerCode = clean(body.seller_code).toUpperCase();
  const amount = Number(body.amount);
  const rate = Number(body.commission_rate || 10);
  const customer = clean(body.customer_name || "Cliente");

  if (!sellerCode || amount <= 0 || rate < 0) throw new Error("Informe código, valor da venda e comissão.");

  const seller = await env.DB.prepare("SELECT * FROM users WHERE code=? AND role='seller' AND active=1").bind(sellerCode).first();
  if (!seller) throw new Error("Código da divulgadora não encontrado.");

  const commission = Math.round((amount * rate / 100) * 100) / 100;

  await env.DB.prepare(`
    INSERT INTO sales (seller_id,seller_code,amount,commission_rate,commission_amount,customer_name,status,paid,created_at)
    VALUES (?,?,?,?,?,?,?,0,datetime('now'))
  `).bind(seller.id, sellerCode, amount, rate, commission, customer, "confirmed").run();

  return { ok: true, commission_amount: commission };
}

async function markPaid(env, body) {
  const sellerCode = clean(body.seller_code || "").toUpperCase();
  if (!sellerCode) throw new Error("Informe o código da divulgadora.");
  await env.DB.prepare("UPDATE sales SET paid=1 WHERE seller_code=? AND paid=0").bind(sellerCode).run();
  return { ok: true };
}

async function requestWithdraw(env, user) {
  const totals = await env.DB.prepare("SELECT COALESCE(SUM(commission_amount),0) amount FROM sales WHERE seller_id=? AND paid=0").bind(user.id).first();
  if (!totals.amount || totals.amount <= 0) throw new Error("Não há comissão pendente para saque.");

  await env.DB.prepare("INSERT INTO withdraw_requests (seller_id,amount,status,created_at) VALUES (?,?,?,datetime('now'))")
    .bind(user.id, totals.amount, "pending").run();

  return { ok: true, amount: totals.amount };
}

async function requireAdmin(request, env) {
  const user = await requireUser(request, env);
  if (user.role !== "admin") throw new Error("Acesso permitido apenas para o dono.");
  return user;
}

async function requireSeller(request, env) {
  const user = await requireUser(request, env);
  if (user.role !== "seller") throw new Error("Acesso permitido apenas para divulgadora.");
  return user;
}

async function requireUser(request, env) {
  const cookie = request.headers.get("Cookie") || "";
  const token = cookie.split(";").map(v=>v.trim()).find(v=>v.startsWith("pf_session="))?.split("=")[1];
  if (!token) throw new Error("Não autenticado.");

  const payload = await verifyToken(token, env);
  const user = await env.DB.prepare("SELECT * FROM users WHERE id=? AND active=1").bind(payload.id).first();
  if (!user) throw new Error("Usuário inválido.");
  return user;
}

function publicUser(user) {
  return { id: user.id, name: user.name, email: user.email, role: user.role, code: user.code };
}

function clean(v) { return String(v || "").trim(); }

async function hashPassword(password) {
  const salt = crypto.getRandomValues(new Uint8Array(16));
  const key = await crypto.subtle.importKey("raw", enc(password), "PBKDF2", false, ["deriveBits"]);
  const bits = await crypto.subtle.deriveBits({ name:"PBKDF2", salt, iterations:100000, hash:"SHA-256" }, key, 256);
  return `pbkdf2$${b64(salt)}$${b64(new Uint8Array(bits))}`;
}

async function verifyPassword(password, stored) {
  const [type, saltB64, hashB64] = stored.split("$");
  if (type !== "pbkdf2") return false;
  const salt = fromB64(saltB64);
  const key = await crypto.subtle.importKey("raw", enc(password), "PBKDF2", false, ["deriveBits"]);
  const bits = await crypto.subtle.deriveBits({ name:"PBKDF2", salt, iterations:100000, hash:"SHA-256" }, key, 256);
  return b64(new Uint8Array(bits)) === hashB64;
}

async function signToken(payload, env) {
  const secret = env.JWT_SECRET || "troque-este-segredo";
  const body = b64url(enc(JSON.stringify(payload)));
  const sig = await hmac(body, secret);
  return `${body}.${sig}`;
}

async function verifyToken(token, env) {
  const [body, sig] = token.split(".");
  if (!body || !sig) throw new Error("Sessão inválida.");
  const expected = await hmac(body, env.JWT_SECRET || "troque-este-segredo");
  if (expected !== sig) throw new Error("Sessão inválida.");
  const payload = JSON.parse(dec(fromB64url(body)));
  if (payload.exp < Math.floor(Date.now()/1000)) throw new Error("Sessão expirada.");
  return payload;
}

async function hmac(data, secret) {
  const key = await crypto.subtle.importKey("raw", enc(secret), { name:"HMAC", hash:"SHA-256" }, false, ["sign"]);
  const sig = await crypto.subtle.sign("HMAC", key, enc(data));
  return b64url(new Uint8Array(sig));
}

function enc(s){ return new TextEncoder().encode(s); }
function dec(a){ return new TextDecoder().decode(a); }
function b64(arr){ return btoa(String.fromCharCode(...arr)); }
function fromB64(s){ return Uint8Array.from(atob(s), c=>c.charCodeAt(0)); }
function b64url(arr){ return b64(arr).replaceAll("+","-").replaceAll("/","_").replaceAll("=",""); }
function fromB64url(s){ s=s.replaceAll("-","+").replaceAll("_","/"); while(s.length%4)s+="="; return fromB64(s); }

function json(data, headers={}, status=200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { "content-type": "application/json;charset=UTF-8", ...headers }
  });
}

function htmlResponse(html) {
  return new Response(html, { headers: { "content-type": "text/html;charset=UTF-8" } });
}

function serveLogo() {
  const b64data = "";
  if (!b64data) return new Response("", { status: 404 });
  const bin = atob(b64data);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return new Response(bytes, { headers: { "content-type": "image/png", "cache-control": "public, max-age=86400" } });
}
